-- Seed meals (idempotent). Каталог у проді змінюй у БД; цей файл — початковий знімок для міграцій.

on conflict (id) do update set
  meal_occasion_id = excluded.meal_occasion_id,
  name = excluded.name,
  calories = excluded.calories,
  protein = excluded.protein,
  fat = excluded.fat,
  carbs = excluded.carbs,
  ingredients = excluded.ingredients,
  updated_at = now();
